-- ==============================================================================
-- 500 REALISTIC E-COMMERCE PRODUCTS FOR A PROFESSIONAL USA ONLINE STORE
-- Generated dynamically: 2026-05-31
-- Target Database Engine: Microsoft SQL Server (SQL Server 2016+)
-- Products count: 500 total (Exactly 125 products per category)
-- Price limits: $100 to $4000 (US Dollars)
-- ==============================================================================

-- 1. Create schema structure if not exists
IF OBJECT_ID('dbo.Products', 'U') IS NOT NULL
    DROP TABLE dbo.Products;
GO

CREATE TABLE dbo.Products (
    ProductID INT IDENTITY(1,1) PRIMARY KEY,
    SKU NVARCHAR(50) NOT NULL UNIQUE,
    Name NVARCHAR(255) NOT NULL,
    Price DECIMAL(18, 2) NOT NULL,
    Stock INT NOT NULL,
    ShortDescription NVARCHAR(500) NOT NULL,
    LongDescription NVARCHAR(MAX) NOT NULL,
    Category NVARCHAR(100) NOT NULL,
    Specifications NVARCHAR(MAX) NULL
);
GO

-- 2. Clear out any existing rows & disable identity inserts if explicitly defined
SET NOCOUNT ON;
GO

PRINT 'Commencing bulk inserts of 500 products...';

INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-APL-IP16PM-256GB-DES-100', N'Apple iPhone 16 Pro Max (256GB, Desert Titanium, Unlocked)', 1199, 8, N'Apple iPhone 16 Pro Max (256GB, Desert Titanium, Unlocked). The ultimate flagship device with a glorious 6.9-inch screen and A18 Pro chip. Retail grade stock curated for USA shoppers.', N'The pinnacle of mobile hardware engineering. Wrapped inside an aerospace-grade Grade 5 titanium chassis, this device features a stunning 6.9-inch Super Retina XDR screen with ultra-thin bezels. Powered by the A18 Pro chip with custom Neural Engine for seamless AI tasks, combined with an advanced telephoto camera, and tactile physical camera slider control. This premium bundle features an optimized setup with hand-selected Desert Titanium aesthetics and configured 256GB physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Apple","Model":"iPhone 16 Pro Max","Display":"6.9\" Super Retina XDR OLED","Processor":"A18 Pro","Chassis":"Grade 5 Titanium","Storage/Config":"256GB","Color Finish":"Desert Titanium","Standard Inventory Group":"USA Retail Center"}');
