INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-APL-MBP14-512GB-SPA-102', N'Apple MacBook Pro 14-inch M4 Pro (512GB SSD, Space Black, Unlocked)', 2024, 16, N'Apple MacBook Pro 14-inch M4 Pro (512GB SSD, Space Black, Unlocked). Hyper-efficient professional power in a portable 14-inch form factor. Retail grade stock curated for USA shoppers.', N'Engineered for designers, developers, and creators. The Apple MacBook Pro runs on the custom-silicon M4 Pro chip with a 14-core CPU and 20-core GPU. Outfitted with Liquid Retina XDR display yielding up to 1600 nits peak luminance and high-speed Thunderbolt 4 physical interfaces. This premium bundle features an optimized setup with hand-selected Space Black aesthetics and configured 512GB SSD physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Apple","Model":"MacBook Pro 14\"","Display":"14.2\" Liquid Retina XDR","Processor":"Apple M4 Pro","Battery":"Up to 22 Hours","Storage/Config":"512GB SSD","Color Finish":"Space Black","Standard Inventory Group":"USA Retail Center"}');
