VALUES (N'TEC-SNY-BR75-STAND-CHA-124', N'Sony Bravia-XR 75-inch Mini-LED 4K TV (Standard Stand, Charcoal Brushed Slate, Unlocked)', 2498, 39, N'Sony Bravia-XR 75-inch Mini-LED 4K TV (Standard Stand, Charcoal Brushed Slate, Unlocked). Cinematic full-array mini-LED display with Cognitive Processor XR. Retail grade stock curated for USA shoppers.', N'Transform your home theater. Thousands of high-density Mini-LEDs are managed by XR Backlight Master Drive to output absolute contrast and blinding peak brightness. Sound is emitted directly from the screen surface using Acoustic Multi-Audio physical actuators. This premium bundle features an optimized setup with hand-selected Charcoal Brushed Slate aesthetics and configured Standard Stand physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Sony","Model":"Bravia XR75-X95L","Display":"75\" 4K Mini-LED","Refresh Rate":"120Hz","Smart TV":"Google TV Platform","Storage/Config":"Standard Stand","Color Finish":"Charcoal Brushed Slate","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-DJI-M3PC-CINEP-MAT-125', N'DJI Mavic 3 Pro Cine Drone (Cine Premium Pack, Matte Aero Gray, Unlocked)', 3011.5, 43, N'DJI Mavic 3 Pro Cine Drone (Cine Premium Pack, Matte Aero Gray, Unlocked). Flagship aerial cinematography drone with triple Hasselblad camera system. Retail grade stock curated for USA shoppers.', N'Re-envisioning expert aerial photography. Sports a world-class primary Hasselblad camera harboring a massive 4/3 CMOS sensor alongside dual telephoto physical lenses. Supports professional-grade Apple ProRes 422 HQ recording, omnidirectional smart obstacle sensing, and extended hover times. This premium bundle features an optimized setup with hand-selected Matte Aero Gray aesthetics and configured Cine Premium Pack physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"DJI","Model":"Mavic 3 Pro Cine","Sensor":"4/3 Hasselblad CMOS","Video Format":"ProRes 422 HQ","Max Range":"15 km","Storage/Config":"Cine Premium Pack","Color Finish":"Matte Aero Gray","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-BSE-QCU-STAND-CAR-126', N'Bose QuietComfort Ultra Wireless Headphones (Standard Travel Set, Carbon Black, Unlocked)', 454, 47, N'Bose QuietComfort Ultra Wireless Headphones (Standard Travel Set, Carbon Black, Unlocked). The pinnacle of active noise-canceling headsets with immersive spatial audio. Retail grade stock curated for USA shoppers.', N'Immerse yourself completely in high-fidelity sound. Employs world-class active hybrid active noise cancellation, custom sound profiles mapped to your ear canals (CustomTune), robust Bluetooth 5.3 connectivity, and up to 24 hours of stable playback. This premium bundle features an optimized setup with hand-selected Carbon Black aesthetics and configured Standard Travel Set physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Bose","Model":"QuietComfort Ultra","Battery":"Up to 24 Hours","ANC":"World-Class Active","Bluetooth":"v5.3 Multipoint","Storage/Config":"Standard Travel Set","Color Finish":"Carbon Black","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-SNS-ARC-STAND-PRE-127', N'Sonos Arc Premium Spatial Dolby Atmos Soundbar (Standalone Soundbar, Premium Matte White, Unlocked)', 936.5, 51, N'Sonos Arc Premium Spatial Dolby Atmos Soundbar (Standalone Soundbar, Premium Matte White, Unlocked). Immersive 3D home audio centerpiece with dual dedicated upward-firing drivers. Retail grade stock curated for USA shoppers.', N'Elevate your audio setup. Brings movies, games, and music to life with eleven high-performance physical driver arrays, including customized custom upward-firing drivers for true spatial Atmos ceiling-reflection grids. This premium bundle features an optimized setup with hand-selected Premium Matte White aesthetics and configured Standalone Soundbar physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Sonos","Model":"Arc Atmos","Channels":"5.0.2 Audio Output","Input":"eARC / Optical HDMI","Voice Assistant":"Alexa & Sonos Mic","Storage/Config":"Standalone Soundbar","Color Finish":"Premium Matte White","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-CAN-EOSR6-BODYO-HIG-128', N'Canon EOS R6 Mark II Mirrorless Camera (Body Only, High-Impact Black Matte, Unlocked)', 2549, 55, N'Canon EOS R6 Mark II Mirrorless Camera (Body Only, High-Impact Black Matte, Unlocked). High-speed hybrid creator camera with 24.2MP CMOS sensor & dual pixel AF. Retail grade stock curated for USA shoppers.', N'A formidable hybrid tool for wedding, scenery, and motion creators. The R6 Mark II features continuous electronic high-speed shutter bursts up to 40fps, uncropped 4K 60fps oversampled from 6K, and unmatched deep learning autofocus auto-tracking. This premium bundle features an optimized setup with hand-selected High-Impact Black Matte aesthetics and configured Body Only physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Canon","Model":"EOS R6 MK II","Sensor":"24.2MP Full-Frame CMOS","Video":"4K 60p Oversampled","Stabilization":"In-Body IS (Up to 8 stops)","Storage/Config":"Body Only","Color Finish":"High-Impact Black Matte","Standard Inventory Group":"USA Retail Center"}');
