INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-APL-IP16PM-256GB-WHI-130', N'Apple iPhone 16 Pro Max (256GB, White Titanium, Unlocked)', 1199, 63, N'Apple iPhone 16 Pro Max (256GB, White Titanium, Unlocked). The ultimate flagship device with a glorious 6.9-inch screen and A18 Pro chip. Retail grade stock curated for USA shoppers.', N'The pinnacle of mobile hardware engineering. Wrapped inside an aerospace-grade Grade 5 titanium chassis, this device features a stunning 6.9-inch Super Retina XDR screen with ultra-thin bezels. Powered by the A18 Pro chip with custom Neural Engine for seamless AI tasks, combined with an advanced telephoto camera, and tactile physical camera slider control. This premium bundle features an optimized setup with hand-selected White Titanium aesthetics and configured 256GB physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Apple","Model":"iPhone 16 Pro Max","Display":"6.9\" Super Retina XDR OLED","Processor":"A18 Pro","Chassis":"Grade 5 Titanium","Storage/Config":"256GB","Color Finish":"White Titanium","Standard Inventory Group":"USA Retail Center"}');
