INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-DEL-XPS16-1TBNV-GRA-173', N'Dell XPS 16 Touch Laptop (1TB NVMe, Graphite Gray, Unlocked)', 2311.5, 40, N'Dell XPS 16 Touch Laptop (1TB NVMe, Graphite Gray, Unlocked). Intel Core Ultra 9 workstation with gorgeous modern CNC block aluminum casing. Retail grade stock curated for USA shoppers.', N'Uncompromised performance. Styled with flawless CNC block aluminum and seamless glass touchpad overlay. Runs on the Intel Core Ultra 9 with AI acceleration, teamed up with NVIDIA GeForce RTX 4060 graphics and a breathtaking organic InfinityEdge touch display. This premium bundle features an optimized setup with hand-selected Graphite Gray aesthetics and configured 1TB NVMe physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Dell","Model":"XPS 16 9640","Display":"16.3\" 4K+ OLED Touch","Processor":"Intel Core Ultra 9 185H","Graphics":"NVIDIA RTX 4060","Storage/Config":"1TB NVMe","Color Finish":"Graphite Gray","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-SNY-BR75-STAND-CHA-174', N'Sony Bravia-XR 75-inch Mini-LED 4K TV (Standard Stand, Charcoal Brushed Slate, Unlocked)', 2523, 44, N'Sony Bravia-XR 75-inch Mini-LED 4K TV (Standard Stand, Charcoal Brushed Slate, Unlocked). Cinematic full-array mini-LED display with Cognitive Processor XR. Retail grade stock curated for USA shoppers.', N'Transform your home theater. Thousands of high-density Mini-LEDs are managed by XR Backlight Master Drive to output absolute contrast and blinding peak brightness. Sound is emitted directly from the screen surface using Acoustic Multi-Audio physical actuators. This premium bundle features an optimized setup with hand-selected Charcoal Brushed Slate aesthetics and configured Standard Stand physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"Sony","Model":"Bravia XR75-X95L","Display":"75\" 4K Mini-LED","Refresh Rate":"120Hz","Smart TV":"Google TV Platform","Storage/Config":"Standard Stand","Color Finish":"Charcoal Brushed Slate","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'TEC-DJI-M3PC-CINEP-MAT-175', N'DJI Mavic 3 Pro Cine Drone (Cine Premium Pack, Matte Aero Gray, Unlocked)', 3036.5, 48, N'DJI Mavic 3 Pro Cine Drone (Cine Premium Pack, Matte Aero Gray, Unlocked). Flagship aerial cinematography drone with triple Hasselblad camera system. Retail grade stock curated for USA shoppers.', N'Re-envisioning expert aerial photography. Sports a world-class primary Hasselblad camera harboring a massive 4/3 CMOS sensor alongside dual telephoto physical lenses. Supports professional-grade Apple ProRes 422 HQ recording, omnidirectional smart obstacle sensing, and extended hover times. This premium bundle features an optimized setup with hand-selected Matte Aero Gray aesthetics and configured Cine Premium Pack physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Tech & Electronics', N'{"Brand":"DJI","Model":"Mavic 3 Pro Cine","Sensor":"4/3 Hasselblad CMOS","Video Format":"ProRes 422 HQ","Max Range":"15 km","Storage/Config":"Cine Premium Pack","Color Finish":"Matte Aero Gray","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
