INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'APP-CGO-EXPD-SIZEX-MIL-221', N'Canada Goose Expedition Protective Winter Parka - Military Sage Green (Size: Size XL)', 1507.5, 37, N'Canada Goose Expedition Protective Winter Parka - Military Sage Green (Size: Size XL). The ultimate polar parka, designed for the extreme field laboratories. Retail grade stock curated for USA shoppers.', N'Engineered to survive deep arctic conditions down to -30°C. Sourced using dense 625-fill power pristine white duck down, physical heavy weather Arctic-Tech canvas outer fabrics, adjustable down-hood liners, and deep-pocket gear storage lines. This premium bundle features an optimized setup with hand-selected Military Sage Green aesthetics and configured Size XL physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Apparel & Luxury Fashion', N'{"Brand":"Canada Goose","Style":"Expedition","Insulation":"625 Fill Power Duck Down","Comfort Rating":"-30°C Level 5","Size / Fit":"Size XL","Item Color":"Military Sage Green","Standard Inventory Group":"USA Retail Center"}');
