INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'FUR-HML-AERON-SIZEB-MIN-100', N'Herman Miller Aeron Ergonomic Task Chair - Mineral Satin, Size B Standard Spec', 1895, 8, N'Herman Miller Aeron Ergonomic Task Chair - Mineral Satin, Size B Standard Spec. The definitive gold standard office task chair with custom Pellicle 8Z mesh. Retail grade stock curated for USA shoppers.', N'Perfect ergonomic support designed to prevent muscle fatigue. Employs advanced Pellicle 8Z mesh yielding eight distinct comfort tension fields. Features state-of-the-art PostureFit SL double lumbar pads, fully-adjustable armrest configurations, and smooth passive tilt controls. This premium bundle features an optimized setup with hand-selected Mineral Satin aesthetics and configured Size B Standard Spec physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Furniture & Living', N'{"Brand":"Herman Miller","Model":"Aeron Size B","Material":"Post-Consumer Recycled Ocean Plastics, Steel","Mesh":"Pellicle 8Z Suspension","Wood/Layout Option":"Size B Standard Spec","Upholstery/Finish Description":"Mineral Satin","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
