INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
VALUES (N'FUR-PBN-FMDIN-60INC-RIC-119', N'Pottery Barn Farmhouse Reclaimed Oak Dining Table - Rich Espresso Espresso Antique, 60-Inch Length (Seats up to 6)', 1511.5, 19, N'Pottery Barn Farmhouse Reclaimed Oak Dining Table - Rich Espresso Espresso Antique, 60-Inch Length (Seats up to 6). Solid dining center made from 100% reclaimed pine and oak boards. Retail grade stock curated for USA shoppers.', N'Artisanal family table that highlights natural wood grains. Every dining table boasts unique natural beauty with subtle cracks, wood knots, and warm grain highlights preserved using hand-buffed protective wax seal coatings. Supported by robust heavy block dynamic support legs. This premium bundle features an optimized setup with hand-selected Rich Espresso Espresso Antique aesthetics and configured 60-Inch Length (Seats up to 6) physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Furniture & Living', N'{"Brand":"Pottery Barn","Style":"Rustic Farmhouse","Material":"100% Reclaimed Pine & solid French Oak","Finish":"Multi-Step Hand Shield Wax","Wood/Layout Option":"60-Inch Length (Seats up to 6)","Upholstery/Finish Description":"Rich Espresso Espresso Antique","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
