VALUES (N'FUR-EAM-LNCSET-STAND-CRE-164', N'Eames Lounge Chair and Ottoman Set Premium - Cream Leather & White Oak, Standard Swivel Spec', 3545, 69, N'Eames Lounge Chair and Ottoman Set Premium - Cream Leather & White Oak, Standard Swivel Spec. The timeless American mid-century classic chair in premium leather and walnut wood veneer. Retail grade stock curated for USA shoppers.', N'The absolute landmark modern masterpiece. Hand-crafted using 7-ply thick real hardwood veneers. Lined with beautiful premium full-grain leather cushions. Mounted onto custom die-cast solid aluminum swivel bases. Perfect for deep office study corners or architectural luxury lounges. This premium bundle features an optimized setup with hand-selected Cream Leather & White Oak aesthetics and configured Standard Swivel Spec physical specifications. Packaged inside impact-cushioned freight storage containers with certificates of authenticity and fully guaranteed consumer services.', N'Furniture & Living', N'{"Brand":"Herman Miller / Eames","Style":"Classic Lounge","Leather":"MCL Italian Full-Grain Leather","Veneer":"7-Ply Santos Palisander / Walnut","Wood/Layout Option":"Standard Swivel Spec","Upholstery/Finish Description":"Cream Leather & White Oak","Standard Inventory Group":"USA Retail Center"}');
INSERT INTO dbo.Products (SKU, Name, Price, Stock, ShortDescription, LongDescription, Category, Specifications)
